"""
measure-phase-e.py — Standing-Wave Mesh Phase E end-to-end measurement.

Goal: quantify bytes-on-wire, per-layer roundtrip count, and wall-clock for
three configs (dense baseline / HCEM-only / HCEM+sketches) across three
prompts (short / medium / long), against the production cobordism shards
deployed at `https://worker-cobordism-s{0..7}.taylorbuley.workers.dev`.

Honest scope note (Phase E reality check)
-----------------------------------------
The P0 production unblock deployed worker-cobordism shards plus
worker-node1 / worker-node2. The follow-on qwen-coder sketch upload
bound `SKETCH_URL` to `models/qwen-coder-7b-sketches.knot`, whose
`output.weight` sketch has `d_in=3584`, matching the deployed
qwen-coder hidden state.

What this script honestly measures against the live mesh:

  - `/cobordism-embed`: full fan-out across 8 shards, real bandwidth +
    wall-clock for tokenization → embedding (Phase A region).
  - `/cobordism-lm-head` dense: full fan-out across 8 shards, real
    bandwidth + wall-clock with a synthesised last-token residual.
    Bytes-on-wire are production-shape; only the residual values
    are synthetic since we can't run a real forward without layer
    workers.
  - `/cobordism-lm-head?sketch=1&top_k={top_k}`: live qwen-coder sketch
    route, using the same one-row f32 octet-stream residual body as dense
    lm-head (14336 bytes per shard) while receiving only sketch results.

Paris-quality decode is N/A in this script: even with layer workers
healthy, this measurement does not orchestrate the full 28-layer forward
pass between embed and lm-head.
"""

from __future__ import annotations

import concurrent.futures
import json
import math
import os
import sys
import time
from dataclasses import dataclass, field
from typing import Optional

import numpy as np
import requests

# ──────────────────────────────────────────────────────────────────────────
# Mesh topology — production endpoints
# ──────────────────────────────────────────────────────────────────────────

COBORDISM_BASE = "https://worker-cobordism-s{shard}.taylorbuley.workers.dev"
COBORDISM_SHARDS = list(range(8))
LAYER_WORKER_BASES = {
    "worker-node1": "https://distributed-inference-worker-node1.taylorbuley.workers.dev",
    "worker-node2": "https://distributed-inference-worker-node2.taylorbuley.workers.dev",
}

# Qwen2.5-Coder-7B-Instruct config (matches the deployed knot).
HIDDEN_DIM = 3584
VOCAB_SIZE = 152064
SHARD_TOKENS = 18992  # except s7 which absorbs the +60 remainder; the
                      # per-shard /health response confirms exact values.

# Per-shard vocab slice as configured in apps/worker-cobordism/aeon.toml.
SHARD_VOCAB_RANGES = [
    (0, 18992), (18992, 37984), (37984, 56976), (56976, 75968),
    (75968, 94960), (94960, 113952), (113952, 132944), (132944, 152064),
]

TOP_K_DEFAULT = 50  # matches the cobordism worker's default top_k

REQUEST_TIMEOUT = 60.0


# ──────────────────────────────────────────────────────────────────────────
# Prompts
# ──────────────────────────────────────────────────────────────────────────

PROMPT_SHORT = "What is the capital of France?"

PROMPT_MEDIUM = (
    "Could you explain how HTTP caching works in a modern web application? "
    "Specifically I want to understand the difference between Cache-Control, "
    "ETag, and Last-Modified headers, when each one is used by browsers and "
    "CDNs, and how a developer should choose between them when designing a "
    "REST API."
)

PROMPT_LONG = (
    "The following passage is excerpted from a longer essay on distributed "
    "systems theory:\n\n"
    "Consensus protocols such as Raft and Paxos exist to provide a single "
    "agreed-upon order of events across a cluster of nodes that may fail or "
    "disagree about the state of the world. Raft, introduced by Ongaro and "
    "Ousterhout, decomposes the consensus problem into three sub-problems: "
    "leader election, log replication, and safety. A single leader receives "
    "client requests and appends them to its log, then replicates each entry "
    "to a quorum of followers before committing it. If the leader fails, a "
    "follower with an up-to-date log can be elected as the new leader. The "
    "key safety invariant is that once an entry is committed at a given index "
    "by some leader, no future leader will ever commit a conflicting entry at "
    "that same index. This is enforced by the election rules: a candidate "
    "cannot win an election unless its log is at least as up to date as the "
    "logs of a majority of the cluster. Practical Byzantine Fault Tolerance "
    "(PBFT) is a related but stronger protocol that tolerates not just crash "
    "failures but also arbitrary (Byzantine) faults at the cost of requiring "
    "3f+1 replicas to tolerate f faults, rather than 2f+1 for crash-only.\n\n"
    "Question: According to the passage, what is the minimum number of "
    "replicas PBFT requires to tolerate f Byzantine faults, and how does "
    "that compare to crash-fault-tolerant Raft?"
)


# ──────────────────────────────────────────────────────────────────────────
# Tokenization
# ──────────────────────────────────────────────────────────────────────────

def tokenize_qwen(prompt: str) -> list[int]:
    """Tokenize against Qwen2.5-Coder-7B-Instruct tokenizer.

    Falls back gracefully if HF Hub is unreachable — we cache the loaded
    tokenizer at module level.
    """
    from transformers import AutoTokenizer  # local import keeps startup fast
    tok = AutoTokenizer.from_pretrained(
        "Qwen/Qwen2.5-Coder-7B-Instruct",
        trust_remote_code=False,
    )
    ids = tok.encode(prompt, add_special_tokens=True)
    return ids


# ──────────────────────────────────────────────────────────────────────────
# Wire-level helpers
# ──────────────────────────────────────────────────────────────────────────

@dataclass
class CallStat:
    """One HTTP call's cost accounting."""
    label: str
    bytes_sent: int
    bytes_recv: int
    elapsed_ms: float
    status: int

    @property
    def bytes_total(self) -> int:
        return self.bytes_sent + self.bytes_recv


@dataclass
class ConfigResult:
    """All call stats for one (prompt, config) pair."""
    prompt_label: str
    config_label: str
    num_tokens: int
    calls: list[CallStat] = field(default_factory=list)
    wall_clock_ms: float = 0.0

    def total_bytes(self) -> int:
        return sum(c.bytes_total for c in self.calls)

    def num_roundtrips(self) -> int:
        return len(self.calls)


def post_with_stats(
    url: str,
    body: bytes,
    headers: dict[str, str],
    label: str,
    timeout: float = REQUEST_TIMEOUT,
) -> tuple[bytes, CallStat]:
    """POST `body` to `url`, returning (response_bytes, CallStat).

    `bytes_sent` counts the HTTP body only (headers are <1 KB and roughly
    constant across configs, so we keep the accounting at the application
    layer — what the task spec calls "bytes-on-wire" for the inference
    payload). This is the same convention the existing host code uses.
    """
    t0 = time.perf_counter()
    resp = requests.post(url, data=body, headers=headers, timeout=timeout)
    elapsed_ms = (time.perf_counter() - t0) * 1000.0
    return resp.content, CallStat(
        label=label,
        bytes_sent=len(body),
        bytes_recv=len(resp.content),
        elapsed_ms=elapsed_ms,
        status=resp.status_code,
    )


# ──────────────────────────────────────────────────────────────────────────
# Cobordism shard calls
# ──────────────────────────────────────────────────────────────────────────

def call_cobordism_embed_shard(
    shard: int, token_ids: list[int]
) -> tuple[np.ndarray, CallStat]:
    """Call /cobordism-embed on one shard. Returns the partial F32 embeddings
    (shape `[len(token_ids), HIDDEN_DIM]`) and call stats.
    """
    url = COBORDISM_BASE.format(shard=shard) + "/cobordism-embed"
    body = np.array(token_ids, dtype=np.uint32).tobytes()
    headers = {"Content-Type": "application/octet-stream"}
    raw, stat = post_with_stats(url, body, headers, f"s{shard}/embed")
    if stat.status != 200:
        raise RuntimeError(f"shard {shard} /embed HTTP {stat.status}: {raw[:200]!r}")
    arr = np.frombuffer(raw, dtype=np.float32).reshape(len(token_ids), HIDDEN_DIM)
    return arr, stat


def fan_out_embed(token_ids: list[int]) -> tuple[np.ndarray, list[CallStat]]:
    """Fan out /cobordism-embed across all 8 shards in parallel and
    Frobenius-merge (elementwise sum, since the shards' vocab slices are
    disjoint — at most one shard contributes nonzero per token row).
    """
    stats: list[CallStat] = []
    merged = np.zeros((len(token_ids), HIDDEN_DIM), dtype=np.float32)
    with concurrent.futures.ThreadPoolExecutor(max_workers=8) as ex:
        futures = {
            ex.submit(call_cobordism_embed_shard, s, token_ids): s
            for s in COBORDISM_SHARDS
        }
        for fut in concurrent.futures.as_completed(futures):
            partial, stat = fut.result()
            merged += partial
            stats.append(stat)
    return merged, stats


def call_cobordism_lmhead_dense_shard(
    shard: int, residual: np.ndarray, seq_len: int
) -> tuple[np.ndarray, CallStat]:
    """Dense lm-head: send the full f32 residual buffer, get back the
    shard's partial-vocab logits as an f32 octet-stream.
    """
    url = COBORDISM_BASE.format(shard=shard) + "/cobordism-lm-head"
    body = residual.astype(np.float32).tobytes()
    headers = {
        "Content-Type": "application/octet-stream",
        "X-Sequence-Length": str(seq_len),
    }
    raw, stat = post_with_stats(url, body, headers, f"s{shard}/lmh-dense")
    if stat.status != 200:
        raise RuntimeError(f"shard {shard} /lmh-dense HTTP {stat.status}: {raw[:200]!r}")
    arr = np.frombuffer(raw, dtype=np.float32)
    return arr, stat


def call_cobordism_lmhead_sketch_shard(
    shard: int, residual_last: np.ndarray, top_k: int
) -> tuple[Optional[dict], CallStat]:
    """Sketch lm-head: send the LAST token's f32 hidden state as bytes.

    The sketch route reads `top_k` from the query string and receives a
    single residual row (`X-Sequence-Length: 1`), matching the dense
    lm-head input shape with a fixed 14336-byte request body.

    Returns (parsed_json, stat) on 200 and (None, stat) on non-200 so the
    caller can record the failure honestly instead of aborting the whole
    measurement run.
    """
    url = (
        COBORDISM_BASE.format(shard=shard)
        + f"/cobordism-lm-head?sketch=1&top_k={top_k}"
    )
    residual_row = np.asarray(residual_last, dtype=np.float32).reshape(HIDDEN_DIM)
    body = residual_row.tobytes(order="C")
    expected_body_bytes = HIDDEN_DIM * np.dtype(np.float32).itemsize
    if len(body) != expected_body_bytes:
        raise ValueError(
            f"sketch lm-head body must be {expected_body_bytes} bytes, got {len(body)}"
        )
    headers = {
        "Content-Type": "application/octet-stream",
        "X-Sequence-Length": "1",
    }
    t0 = time.perf_counter()
    try:
        raw, stat = post_with_stats(url, body, headers, f"s{shard}/lmh-sketch")
    except requests.RequestException as exc:
        elapsed_ms = (time.perf_counter() - t0) * 1000.0
        return None, CallStat(
            label=f"s{shard}/lmh-sketch",
            bytes_sent=len(body),
            bytes_recv=len(str(exc).encode("utf-8")),
            elapsed_ms=elapsed_ms,
            status=0,
        )
    if stat.status != 200:
        return None, stat
    return json.loads(raw), stat


def fan_out_lmhead_dense(
    residual: np.ndarray, seq_len: int
) -> tuple[np.ndarray, list[CallStat]]:
    """Fan out dense /cobordism-lm-head across all 8 shards in parallel and
    concatenate the partial-vocab logits into a single Vocab-shaped array.
    """
    stats: list[CallStat] = []
    out = np.zeros(VOCAB_SIZE, dtype=np.float32)
    with concurrent.futures.ThreadPoolExecutor(max_workers=8) as ex:
        futures = {
            ex.submit(call_cobordism_lmhead_dense_shard, s, residual, seq_len): s
            for s in COBORDISM_SHARDS
        }
        for fut in concurrent.futures.as_completed(futures):
            s = futures[fut]
            partial, stat = fut.result()
            vs, ve = SHARD_VOCAB_RANGES[s]
            out[vs:ve] = partial
            stats.append(stat)
    return out, stats


def fan_out_lmhead_sketch(
    residual_last: np.ndarray, top_k: int
) -> tuple[list[Optional[dict]], list[CallStat]]:
    """Fan out sketch /cobordism-lm-head?sketch=1&top_k=... across all 8
    shards in parallel. Returns a list of per-shard payloads (None when the
    shard returned non-200) and the call stats. The bandwidth/wall-clock
    numbers are recorded even when the sketch branch returns non-200,
    because the actual bytes sent to and received from the worker are real.
    """
    stats: list[CallStat] = []
    results: list[Optional[dict]] = []
    with concurrent.futures.ThreadPoolExecutor(max_workers=8) as ex:
        futures = {
            ex.submit(call_cobordism_lmhead_sketch_shard, s, residual_last, top_k): s
            for s in COBORDISM_SHARDS
        }
        for fut in concurrent.futures.as_completed(futures):
            payload, stat = fut.result()
            results.append(payload)
            stats.append(stat)
    return results, stats


# ──────────────────────────────────────────────────────────────────────────
# Health probe
# ──────────────────────────────────────────────────────────────────────────

def probe_health() -> dict[str, bool]:
    statuses: dict[str, bool] = {}
    for s in COBORDISM_SHARDS:
        url = COBORDISM_BASE.format(shard=s) + "/health"
        try:
            r = requests.get(url, timeout=10.0)
            statuses[f"cobordism-s{s}"] = r.status_code == 200
        except Exception:
            statuses[f"cobordism-s{s}"] = False
    return statuses


def probe_layer_health() -> dict[str, bool]:
    statuses: dict[str, bool] = {}
    for name, base_url in LAYER_WORKER_BASES.items():
        try:
            r = requests.get(base_url + "/health", timeout=10.0)
            statuses[name] = r.status_code == 200
        except Exception:
            statuses[name] = False
    return statuses


# ──────────────────────────────────────────────────────────────────────────
# Per-config measurement
# ──────────────────────────────────────────────────────────────────────────

def measure_config(
    config_label: str,
    prompt_label: str,
    token_ids: list[int],
    do_embed: bool,
    lmhead_mode: str,  # 'dense' | 'sketch' | 'skip'
) -> ConfigResult:
    """Run one (prompt, config) measurement. Configs differ in:
      - 'dense'   : embed via the current production /cobordism-embed
                    path; lm-head via dense fan-out.
      - 'hcem'    : same public embed route. After the qwen-coder HCEM
                    artifact is wired, this route is HCEM-backed inside
                    the shard but client-visible response bytes stay
                    unchanged because the worker still returns f32 rows.
      - 'hcem+sketch': embed via current production path, lm-head via
                    sketch (?sketch=1).
    """
    result = ConfigResult(prompt_label=prompt_label, config_label=config_label,
                          num_tokens=len(token_ids))
    t_start = time.perf_counter()

    # Embedding step. /cobordism-embed is one fan-out across 8 shards per
    # token batch. The same public path serves the "dense" and "HCEM"
    # labels; HCEM changes the shard's internal row source, not the f32
    # response shape observed by this client.
    residual: np.ndarray | None = None
    if do_embed:
        residual, embed_stats = fan_out_embed(token_ids)
        result.calls.extend(embed_stats)

    # lm-head step. Use a synthesised last-token residual when we haven't
    # actually run the transformer (we can't — layer workers aren't
    # deployed). The embedding itself isn't the right residual for
    # lm-head (a 28-layer transformer would normally transform it), but
    # the BYTES-ON-WIRE for the lm-head call are identical regardless of
    # what's in the f32 buffer. So the bandwidth measurement is real;
    # only the logit values are synthetic.
    if lmhead_mode != "skip":
        if residual is not None:
            # Use the actual last-token embedding as a stand-in for the
            # post-transformer residual. The bytes-on-wire don't care.
            residual_last = residual[-1, :].copy()
        else:
            rng = np.random.default_rng(seed=0xA0FE)
            residual_last = rng.standard_normal(HIDDEN_DIM).astype(np.float32) * (
                1.0 / math.sqrt(HIDDEN_DIM)
            )
        # The dense lm-head expects a [seq_len, hidden] residual; we send
        # just the last token (seq_len=1) since the worker only computes
        # logits for the last row. This is the production wire shape.
        residual_for_dense = residual_last.reshape(1, HIDDEN_DIM)

        if lmhead_mode == "dense":
            _, lmh_stats = fan_out_lmhead_dense(residual_for_dense, seq_len=1)
        elif lmhead_mode == "sketch":
            _, lmh_stats = fan_out_lmhead_sketch(residual_last, top_k=TOP_K_DEFAULT)
        else:
            raise ValueError(f"unknown lmhead_mode {lmhead_mode!r}")
        result.calls.extend(lmh_stats)

    result.wall_clock_ms = (time.perf_counter() - t_start) * 1000.0
    return result


# ──────────────────────────────────────────────────────────────────────────
# Reporting
# ──────────────────────────────────────────────────────────────────────────

def format_kb(n_bytes: int) -> str:
    if n_bytes >= 1024 * 1024:
        return f"{n_bytes / (1024 * 1024):.2f} MiB"
    if n_bytes >= 1024:
        return f"{n_bytes / 1024:.2f} KiB"
    return f"{n_bytes} B"


def main() -> int:
    print("=" * 72)
    print("Standing-Wave Mesh — Phase E measurement")
    print("=" * 72)
    print()

    print("Health probe ...")
    health = probe_health()
    for name, ok in sorted(health.items()):
        print(f"  {name}: {'OK' if ok else 'UNREACHABLE'}")
    layer_health = probe_layer_health()
    for name, ok in sorted(layer_health.items()):
        print(f"  {name}: {'OK' if ok else 'UNREACHABLE'}")
    if not all(health.values()):
        print()
        print("BLOCKER: one or more shards unreachable. Refusing to measure.")
        return 2
    layer_workers_deployed = all(layer_health.values())
    if not layer_workers_deployed:
        print()
        print("NOTE: worker-node1 / worker-node2 health probe did not pass.")
        print("  We measure /cobordism-embed and /cobordism-lm-head honestly and")
        print("  record N/A for end-to-end greedy decode quality.")
    else:
        print()
        print("NOTE: worker-node1 / worker-node2 health checks pass.")
        print("  This script still does not orchestrate the full 28-layer decode.")
    print()

    prompts = [
        ("short",  PROMPT_SHORT),
        ("medium", PROMPT_MEDIUM),
        ("long",   PROMPT_LONG),
    ]
    tokenized: list[tuple[str, list[int]]] = []
    print("Tokenizing prompts against Qwen2.5-Coder-7B-Instruct ...")
    for label, text in prompts:
        ids = tokenize_qwen(text)
        tokenized.append((label, ids))
        print(f"  {label:<6s}: {len(ids):>4d} tokens")
    print()

    # 3 configs × 3 prompts = 9 measurements.
    configs = [
        # config_label,   do_embed, lmhead_mode
        ("dense",        True,      "dense"),
        ("hcem-only",    True,      "dense"),   # see honest note below
        ("hcem+sketch",  True,      "sketch"),
    ]

    all_results: list[ConfigResult] = []
    sketch_path_live = True  # may flip false on first sketch call
    for prompt_label, ids in tokenized:
        for cfg_label, do_embed, lmh_mode in configs:
            print(f"Measuring  prompt={prompt_label:<6s}  config={cfg_label} ...")
            r = measure_config(cfg_label, prompt_label, ids, do_embed, lmh_mode)
            all_results.append(r)
            non200 = [c for c in r.calls if c.status != 200]
            sketch_calls = [c for c in r.calls if "lmh-sketch" in c.label]
            if sketch_calls and any(c.status != 200 for c in sketch_calls):
                sketch_path_live = False
            warn = "" if not non200 else f"  WARN: {len(non200)} non-200"
            print(
                f"  bytes={format_kb(r.total_bytes()):>10s}  "
                f"roundtrips={r.num_roundtrips():>2d}  "
                f"wall={r.wall_clock_ms:>8.1f} ms{warn}"
            )
    print()

    if not sketch_path_live:
        print("NOTE: sketch branch returned non-200.")
        print("  This should be investigated: production SKETCH_URL is expected")
        print("  to point at the qwen-coder-7b sketch artifact.")
        print("  Bandwidth + wall-clock numbers for hcem+sketch above are the rejected-call cost.")
        print()

    # Print the 9-cell table.
    print("9-cell bandwidth table (bytes-on-wire, roundtrips, wall-clock):")
    print()
    print(f"{'prompt':<8s}{'config':<14s}{'tokens':>8s}{'bytes':>14s}{'roundtrips':>13s}{'wall_ms':>11s}")
    print("-" * 68)
    for r in all_results:
        print(f"{r.prompt_label:<8s}{r.config_label:<14s}"
              f"{r.num_tokens:>8d}{format_kb(r.total_bytes()):>14s}"
              f"{r.num_roundtrips():>13d}{r.wall_clock_ms:>11.1f}")
    print()

    # Per-call dense-vs-sketch ratio on lm-head. We pull the lmh calls out
    # of each result and compare matching shard labels.
    print("Sketch reduction ratio (per lm-head call, averaged over 8 shards):")
    by_prompt: dict[str, dict[str, list[CallStat]]] = {}
    for r in all_results:
        by_prompt.setdefault(r.prompt_label, {})
        cfg = r.config_label
        lmh_calls = [c for c in r.calls if "/lmh-" in c.label]
        by_prompt[r.prompt_label][cfg] = lmh_calls
    for p_label, cfgs in by_prompt.items():
        dense = cfgs.get("dense", [])
        sketch = cfgs.get("hcem+sketch", [])
        if dense and sketch:
            dense_bytes_total = sum(c.bytes_total for c in dense)
            sketch_bytes_total = sum(c.bytes_total for c in sketch)
            ratio = dense_bytes_total / max(sketch_bytes_total, 1)
            dense_recv_avg = sum(c.bytes_recv for c in dense) / len(dense)
            sketch_recv_avg = sum(c.bytes_recv for c in sketch) / len(sketch)
            recv_ratio = dense_recv_avg / max(sketch_recv_avg, 1)
            print(
                f"  {p_label:<6s}  fan-out total: {format_kb(dense_bytes_total)} dense -> "
                f"{format_kb(sketch_bytes_total)} sketch  ({ratio:.1f}x)"
            )
            print(
                f"  {p_label:<6s}  recv per shard: {dense_recv_avg:.0f} B dense -> "
                f"{sketch_recv_avg:.0f} B sketch  ({recv_ratio:.1f}x)"
            )
    print()

    print("Paris-quality decode: N/A (not orchestrated by this script).")
    print("  Layer-worker health is recorded above, but this script only measures")
    print("  cobordism embed/lm-head fan-out. Recording full decode as N/A in doc.")
    print()

    # Emit JSON for the doc generator (and for debugging).
    out_json_path = os.environ.get(
        "PHASE_E_JSON",
        "./open-source/gnosis/distributed-inference/measure-phase-e-results.json",
    )
    with open(out_json_path, "w") as f:
        json.dump(
            {
                "health": health,
                "layer_worker_health": layer_health,
                "layer_workers_deployed": layer_workers_deployed,
                "prompts": [
                    {"label": p_label, "num_tokens": len(ids), "first_8_ids": ids[:8]}
                    for p_label, ids in tokenized
                ],
                "results": [
                    {
                        "prompt": r.prompt_label,
                        "config": r.config_label,
                        "num_tokens": r.num_tokens,
                        "total_bytes": r.total_bytes(),
                        "num_roundtrips": r.num_roundtrips(),
                        "wall_clock_ms": round(r.wall_clock_ms, 2),
                        "calls": [
                            {
                                "label": c.label,
                                "bytes_sent": c.bytes_sent,
                                "bytes_recv": c.bytes_recv,
                                "elapsed_ms": round(c.elapsed_ms, 2),
                                "status": c.status,
                            }
                            for c in r.calls
                        ],
                    }
                    for r in all_results
                ],
            },
            f,
            indent=2,
        )
    print(f"Wrote per-call JSON to {out_json_path}")
    return 0


if __name__ == "__main__":
    sys.exit(main())
